"""
reporting module - handles core reporting functionality
"""
from typing import Optional, List
from dataclasses import dataclass

@dataclass
class ReportingService:
    id: int
    name: str
    status: str = "active"
    created_at: Optional[str] = None

    def validate(self) -> bool:
        """Validate the ReportingService instance."""
        if not self.name:
            raise ValueError("Name is required")
        return True

    def to_dict(self) -> dict:
        """Convert to dictionary representation."""
        return {{
            "id": self.id,
            "name": self.name,
            "status": self.status,
            "created_at": self.created_at
        }}

import {{ Injectable }} from '@nestjs/common';
import {{ ReportingService }} from './models/reporting.model';
import {{ ReportingServiceRepository }} from './repositories/reporting.repository';

@Injectable()
export class ReportingServiceService {{
  constructor(
    private readonly repository: ReportingServiceRepository,
  ) {{}}

  async findAll(): Promise<ReportingService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<ReportingService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<ReportingService>): Promise<ReportingService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<ReportingService>): Promise<ReportingService> {{
    return this.repository.update(id, data);
  }}
}}
